def compute_closed_loop_poles(K):
    """Compute closed loop poles for gain K.
    G(s) = K / (s(s+2)(s+4)) = K / (s^3 + 6s^2 + 8s)
    Closed loop: s^3 + 6s^2 + 8s + K = 0
    """
    # Characteristic polynomial: s^3 + 6s^2 + 8s + K
    coeffs = [1, 6, 8, K]
    poles = np.roots(coeffs)
    return poles


def compute_root_locus_path(num_points=300):
    """Compute root locus for a range of gains."""
    gains = np.logspace(np.log10(K_MIN), np.log10(K_MAX), num_points)
    all_poles = []
    for K in gains:
        poles = compute_closed_loop_poles(K)
        # Sort poles by imaginary part for consistent coloring
        poles_sorted = sorted(poles, key=lambda p: p.imag)
        all_poles.append(poles_sorted)
    return gains, all_poles


def compute_step_response(K, t_max=10.0, num_points=500):
    """Compute step response for closed loop system with gain K."""
    # Closed loop TF: K / (s^3 + 6s^2 + 8s + K)
    num = [K]
    den = [1, 6, 8, K]
    sys_cl = signal.TransferFunction(num, den)
    t = np.linspace(0, t_max, num_points)
    try:
        t_out, y_out = signal.step(sys_cl, T=t)
        return t_out, y_out
    except:
        return t, np.zeros_like(t)


def world_to_screen_rl(real, imag, rect, x_range=(-7, 2), y_range=(-8, 8)):
    """Convert complex plane coordinates to screen coordinates for root locus."""
    x_min, x_max = x_range
    y_min, y_max = y_range
    sx = rect.left + (real - x_min) / (x_max - x_min) * rect.width
    sy = rect.top + (1 - (imag - y_min) / (y_max - y_min)) * rect.height
    return int(sx), int(sy)


def world_to_screen_sr(t, y, rect, t_max=10.0, y_min=-0.3, y_max=1.8):
    """Convert time/amplitude to screen coordinates for step response."""
    sx = rect.left + (t / t_max) * rect.width
    sy = rect.top + (1 - (y - y_min) / (y_max - y_min)) * rect.height
    return int(sx), int(sy)


